 76→/// High-level category for an invariant property description.
 77→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
 78→#[serde(rename_all = "snake_case")]
 79→pub enum InvariantCategory {
 80→    NumericBound,
 81→    Nullability,
 82→    StringConstraint,
 83→    ReturnTypeInvariant,
 84→    ErrorInvariant,
 85→    InputOutputRelation,
 86→    BooleanConstant,
 87→    ConstantValue,
 88→}
 89→
 90→/// Categorical confidence derived from the numeric confidence score.
 91→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
 92→#[serde(rename_all = "snake_case")]
 93→pub enum ConfidenceLevel {
 94→    High,
 95→    Medium,
 96→    Low,
 97→}
 98→
 99→const CONFIDENCE_HIGH_THRESHOLD: f64 = 0.95;
100→const CONFIDENCE_MEDIUM_THRESHOLD: f64 = 0.75;
101→
102→impl ConfidenceLevel {
103→    fn from_score(score: f64) -> Self {
104→        if score >= CONFIDENCE_HIGH_THRESHOLD {
105→            Self::High
106→        } else if score >= CONFIDENCE_MEDIUM_THRESHOLD {
107→            Self::Medium
108→        } else {
109→            Self::Low
110→        }
111→    }
112→}
113→
114→/// A human-friendly invariant for YAML spec output.
115→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
116→pub struct SpecInvariant {
117→    /// Human-readable property description.
118→    pub property: String,
119→    /// High-level invariant category.
120→    pub kind: InvariantCategory,
121→    /// Categorical confidence level.
122→    pub confidence: ConfidenceLevel,
123→}
124→
125→impl From<&ClassifiedInvariant> for SpecInvariant {
126→    fn from(ci: &ClassifiedInvariant) -> Self {
127→        Self {
128→            property: ci.label.clone(),
129→            kind: categorize_invariant_kind(&ci.invariant.kind),
130→            confidence: ConfidenceLevel::from_score(ci.confidence),
131→        }
132→    }
133→}
134→
135→fn categorize_invariant_kind(kind: &InvariantKind) -> InvariantCategory {
136→    match kind {
137→        InvariantKind::NumericComparison { .. } => InvariantCategory::NumericBound,
138→        InvariantKind::NumericConstant { .. } => InvariantCategory::ConstantValue,
139→        InvariantKind::NotNull { .. } | InvariantKind::IsNull { .. } => {
140→            InvariantCategory::Nullability
141→        }
142→        InvariantKind::StringNonEmpty { .. } | InvariantKind::StringLength { .. } => {
143→            InvariantCategory::StringConstraint
144→        }
145→        InvariantKind::OutputEqualsInput { .. } => InvariantCategory::InputOutputRelation,
146→        InvariantKind::AlwaysTrue { .. } | InvariantKind::AlwaysFalse { .. } => {
147→            InvariantCategory::BooleanConstant
148→        }
149→    }

