  0→//! Disk cache for [`BehaviorMap`]s, enabling persistence across runs.
  1→//!
  2→//! When shatter explores a function, the resulting behavior map is stored to disk
  3→//! so it can be reloaded in future runs — critical for compositional testing where
  4→//! function B's behavior map is reused when testing function A.
  5→
  6→use std::fs;
  7→use std::path::{Path, PathBuf};
  8→
  9→use crate::behavior::BehaviorMap;
 10→
 11→/// Errors that can occur during cache operations.
 12→#[derive(Debug, thiserror::Error)]
 13→pub enum CacheError {
 14→    #[error("cache I/O error: {0}")]
 15→    Io(#[from] std::io::Error),
 16→    #[error("cache serialization error: {0}")]
 17→    Serialization(#[from] serde_json::Error),
 18→}
 19→
 20→/// Disk-backed cache for storing and loading [`BehaviorMap`]s.
 21→#[derive(Debug)]
 22→pub struct BehaviorMapCache {
 23→    cache_dir: PathBuf,
 24→}
 25→
 26→impl BehaviorMapCache {
 27→    /// Create a new cache backed by the given directory.
 28→    ///
 29→    /// Creates the directory (and parents) if it doesn't exist.
 30→    pub fn new(cache_dir: PathBuf) -> Result<Self, CacheError> {
 31→        fs::create_dir_all(&cache_dir)?;
 32→        Ok(Self { cache_dir })
 33→    }
 34→
 35→    /// Load a behavior map for the given function ID, if one exists.
 36→    ///
 37→    /// Returns `Ok(None)` if no cached map exists for this function.
 38→    pub fn load(&self, function_id: &str) -> Result<Option<BehaviorMap>, CacheError> {
 39→        let path = self.path_for(function_id);
 40→        match fs::read_to_string(&path) {
 41→            Ok(contents) => {
 42→                let map: BehaviorMap = serde_json::from_str(&contents)?;
 43→                Ok(Some(map))
 44→            }
 45→            Err(e) if e.kind() == std::io::ErrorKind::NotFound => Ok(None),
 46→            Err(e) => Err(CacheError::Io(e)),
 47→        }
 48→    }
 49→
 50→    /// Store a behavior map to disk using atomic write (temp file + rename).
 51→    pub fn store(&self, map: &BehaviorMap) -> Result<(), CacheError> {
 52→        let path = self.path_for(&map.function_id);
 53→        let json = serde_json::to_string_pretty(map)?;
 54→
 55→        // Ensure parent directories exist for hierarchical cache paths.
 56→        if let Some(parent) = path.parent() {
 57→            fs::create_dir_all(parent)?;
 58→        }
 59→
 60→        // Atomic write: write to a temp file in the same directory, then rename.
 61→        let tmp_path = path.with_extension("json.tmp");
 62→        fs::write(&tmp_path, json)?;
 63→        fs::rename(&tmp_path, &path)?;
 64→
 65→        Ok(())
 66→    }
 67→
 68→    /// Check whether a cached behavior map exists and its fingerprint matches.
 69→    ///
 70→    /// Returns `true` if the cache contains a map for `function_id` whose
 71→    /// fingerprint equals `current_fingerprint`. Returns `false` if no cached
 72→    /// map exists, the cached map has no fingerprint, or the fingerprints differ.
 73→    pub fn is_fresh(
 74→        &self,
 75→        function_id: &str,
 76→        current_fingerprint: &str,
 77→    ) -> Result<bool, CacheError> {
 78→        match self.load(function_id)? {
 79→            Some(map) => Ok(map
 80→                .fingerprint
 81→                .as_deref()
 82→                .is_some_and(|fp| fp == current_fingerprint)),
 83→            None => Ok(false),
 84→        }
 85→    }
 86→
 87→    /// Default cache directory relative to a project root: `<project_root>/.shatter/cache/`.
 88→    pub fn default_dir(project_root: &Path) -> PathBuf {
 89→        project_root.join(".shatter").join("cache")
 90→    }
 91→
 92→    /// Compute the file path for a given function ID.
 93→    ///
 94→    /// Mirrors the source tree structure:
 95→    /// - `src/auth.ts:validateToken` → `src/auth.ts/validateToken.json`
 96→    /// - `src/auth.ts:TokenValidator.validate` → `src/auth.ts/TokenValidator/validate.json`
 97→    /// - `simpleFunc` (no colon) → `simpleFunc.json`
 98→    fn path_for(&self, function_id: &str) -> PathBuf {
 99→        let mut path = self.cache_dir.clone();
100→
101→        let (file_part, func_part) = match function_id.split_once(':') {
102→            Some((f, func)) => (Some(f), func),
103→            None => (None, function_id),
104→        };
105→
106→        // Append file path components (each sanitized individually).
107→        if let Some(file) = file_part {
108→            for component in file.split('/') {
109→                if !component.is_empty() {
110→                    path.push(sanitize_component(component));
111→                }
112→            }
113→        }
114→
115→        // Split func_part on '.' for class.method.
116→        match func_part.split_once('.') {
117→            Some((class_name, method_name)) => {
118→                path.push(sanitize_component(class_name));
119→                path.push(format!("{}.json", sanitize_component(method_name)));
120→            }
121→            None => {
122→                path.push(format!("{}.json", sanitize_component(func_part)));
123→            }
124→        }
125→
126→        path
127→    }
128→}
129→
130→/// Sanitize a single path component for safe use as a filename.
131→///
132→/// Replaces unsafe characters with underscores to prevent path traversal attacks.
133→/// Called per-component after splitting on `/` and `:`, so those delimiters
134→/// are not expected in the input.
135→fn sanitize_component(component: &str) -> String {
136→    component
137→        .chars()
138→        .enumerate()
139→        .map(|(i, c)| match c {
140→            '\\' | '*' | '?' | '"' | '<' | '>' | '|' | '\0' => '_',
141→            '.' if i == 0 => '_', // prevent hidden files for leading dots
142→            _ => c,
143→        })
144→        .collect()
145→}
