  0→//! Per-function fingerprinting for staleness detection.
  1→//!
  2→//! A fingerprint is a stable SHA-256 hash of a function's source text,
  3→//! parameter types, and branch structure. When a fingerprint matches a
  4→//! previously cached value, the function is unchanged and can be skipped
  5→//! during re-exploration.
  6→
  7→use std::collections::{HashMap, HashSet};
  8→use std::fmt::Write as _;
  9→use std::path::Path;
 10→
 11→use sha2::{Digest, Sha256};
 12→
 13→use crate::protocol::FunctionAnalysis;
 14→
 15→/// Compute a hex-encoded SHA-256 fingerprint for a function.
 16→///
 17→/// The fingerprint incorporates:
 18→/// - The function's source text (verbatim, including whitespace)
 19→/// - Parameter names and types (sorted by name for stability)
 20→/// - Branch structure: IDs, lines, condition text, types (sorted by ID)
 21→///
 22→/// Any change to these inputs produces a different fingerprint.
 23→pub fn compute_function_fingerprint(source_text: &str, analysis: &FunctionAnalysis) -> String {
 24→    let mut hasher = Sha256::new();
 25→
 26→    // Hash source text.
 27→    hasher.update(b"source:");
 28→    hasher.update(source_text.as_bytes());
 29→
 30→    // Hash parameters (sorted by name for determinism).
 31→    let mut params: Vec<_> = analysis
 32→        .params
 33→        .iter()
 34→        .map(|p| {
 35→            let mut s = String::new();
 36→            let _ = write!(s, "{}:{:?}", p.name, p.typ);
 37→            if let Some(ref tn) = p.type_name {
 38→                let _ = write!(s, "/{tn}");
 39→            }
 40→            s
 41→        })
 42→        .collect();
 43→    params.sort();
 44→
 45→    hasher.update(b"params:");
 46→    for p in &params {
 47→        hasher.update(p.as_bytes());
 48→        hasher.update(b"\n");
 49→    }
 50→
 51→    // Hash branch structure (sorted by branch ID for determinism).
 52→    let mut branches: Vec<_> = analysis
 53→        .branches
 54→        .iter()
 55→        .map(|b| {
 56→            let mut s = String::new();
 57→            let _ = write!(s, "{}:{}:{:?}:{}", b.id, b.line, b.branch_type, b.condition_text);
 58→            s
 59→        })
 60→        .collect();
 61→    branches.sort();
 62→
 63→    hasher.update(b"branches:");
 64→    for b in &branches {
 65→        hasher.update(b.as_bytes());
 66→        hasher.update(b"\n");
 67→    }
 68→
 69→    format!("{:x}", hasher.finalize())
 70→}
 71→
 72→/// Compute a deep fingerprint that incorporates callee fingerprints.
 73→///
 74→/// Extends the shallow fingerprint by hashing in the deep fingerprints of all
 75→/// in-scope callees (sorted by name for determinism). Callees not present in
 76→/// `callee_deep_fingerprints` are ignored (they are out-of-scope and assumed stable).
 77→///
 78→/// Because scans process functions leaves-first, callee deep fingerprints are
 79→/// always available before the caller is processed.
 80→pub fn compute_deep_fingerprint(
 81→    shallow_fingerprint: &str,
 82→    callee_deep_fingerprints: &HashMap<String, String>,
 83→    callees: &HashSet<String>,
 84→) -> String {
 85→    let mut hasher = Sha256::new();
 86→    hasher.update(b"shallow:");
 87→    hasher.update(shallow_fingerprint.as_bytes());
 88→
 89→    let mut callee_fps: Vec<(&str, &str)> = callees
 90→        .iter()
 91→        .filter_map(|c| {
 92→            callee_deep_fingerprints
 93→                .get(c)
 94→                .map(|fp| (c.as_str(), fp.as_str()))
 95→        })
 96→        .collect();
 97→    callee_fps.sort_by_key(|(name, _)| *name);
 98→
 99→    hasher.update(b"callees:");
100→    for (name, fp) in &callee_fps {
101→        hasher.update(name.as_bytes());
102→        hasher.update(b"=");
103→        hasher.update(fp.as_bytes());
104→        hasher.update(b"\n");
105→    }
106→
107→    format!("{:x}", hasher.finalize())
108→}
109→
110→/// Compute deep fingerprints for all functions in a single file.
111→///
112→/// For each analysis, computes a shallow fingerprint from source text + metadata,
113→/// then composes it with callee deep fingerprints. Functions are processed in
114→/// dependency order (leaves first via Kahn's algorithm on out-edges) so callee
115→/// fingerprints are available when computing callers. Out-of-scope callees
116→/// (not in `analyses`) are ignored. Cycles are broken by processing remaining
117→/// functions with partial callee fingerprints.
118→///
119→/// Returns a map from function name to deep fingerprint.
120→pub fn compute_deep_fingerprints(
121→    file_path: &Path,
122→    analyses: &[FunctionAnalysis],
123→) -> Result<HashMap<String, String>, std::io::Error> {
124→    let name_set: HashSet<&str> = analyses.iter().map(|a| a.name.as_str()).collect();
125→
126→    // Compute shallow fingerprints for all functions.
127→    let mut shallow: HashMap<String, String> = HashMap::new();
128→    for func in analyses {
129→        let source = extract_function_source(file_path, func.start_line, func.end_line)?;
130→        shallow.insert(func.name.clone(), compute_function_fingerprint(&source, func));
131→    }
132→
133→    // Build in-scope callee sets per function.
134→    let callees_map: HashMap<&str, HashSet<String>> = analyses
135→        .iter()
136→        .map(|func| {
137→            let callees: HashSet<String> = func
138→                .dependencies
139→                .iter()
140→                .map(|d| d.symbol.clone())
141→                .filter(|s| name_set.contains(s.as_str()))
142→                .collect();
143→            (func.name.as_str(), callees)
144→        })
145→        .collect();
146→
147→    // Kahn's algorithm: process leaves (no in-scope callees) first.
148→    // out_degree = number of unprocessed in-scope callees.
149→    let mut out_degree: HashMap<&str, usize> = analyses

600→    let analysis_map: HashMap<&str, &FunctionAnalysis> =
601→        analyses.iter().map(|a| (a.name.as_str(), a)).collect();
602→
603→    let effective_parallelism = config.parallelism.max(1);
604→    let pool = Arc::new(
605→        WorkerPool::spawn(frontend_config, effective_parallelism)
606→            .await
607→            .map_err(ScanError::Frontend)?,
608→    );
609→
610→    let behavior_maps: Arc<Mutex<HashMap<String, BehaviorMap>>> =
611→        Arc::new(Mutex::new(HashMap::new()));
612→
613→    // Load the interesting input pool for cross-function seed sharing.
614→    let input_pool: Arc<Mutex<InterestingPool>> = {
615→        let loaded = config
616→            .pool_path
617→            .as_ref()
618→            .and_then(|p| interesting_pool::load_pool(p).ok().flatten())
619→            .unwrap_or_default();
620→        Arc::new(Mutex::new(loaded))
621→    };
622→    input_pool.lock().await.epoch += 1;
623→
624→    // Deep fingerprints: accumulated across layers. Since functions within a
625→    // layer have no cross-dependencies, callee deep FPs are always from prior
626→    // layers and this map is immutable during within-layer parallel execution.
627→    let mut deep_fingerprints: HashMap<String, String> = HashMap::new();
628→
629→    // Load checkpoint for resume support.
630→    let scan_id = crate::checkpoint::ScanCheckpoint::compute_scan_id(
631→        &config.file_map.values().map(|s| s.as_str()).collect::<Vec<_>>(),
632→    );
633→    let mut checkpoint = match &config.resume_path {
634→        Some(path) => {
635→            match crate::checkpoint::ScanCheckpoint::load(path) {
636→                Ok(Some(cp)) if cp.scan_id == scan_id => cp,
637→                Ok(Some(_)) => {
638→                    log::info!("checkpoint scan_id mismatch, starting fresh");
639→                    crate::checkpoint::ScanCheckpoint::new(scan_id)
640→                }
641→                Ok(None) => crate::checkpoint::ScanCheckpoint::new(scan_id),
642→                Err(e) => {
643→                    log::warn!("failed to load checkpoint: {e}, starting fresh");
644→                    crate::checkpoint::ScanCheckpoint::new(scan_id)
645→                }
646→            }
647→        }
648→        None => crate::checkpoint::ScanCheckpoint::new(scan_id),
649→    };
650→
651→    let mut all_results: Vec<FunctionResult> = Vec::new();
652→    let mut test_order: Vec<String> = Vec::new();
653→    let mut skipped: Vec<SkippedFunction> = Vec::new();
654→
655→    let scan_start = Instant::now();
656→
657→    for (layer_idx, layer) in layers.iter().enumerate() {
658→        // Check total scan timeout at layer boundary.
659→        if let Some(total) = config.timeout_total
660→            && scan_start.elapsed() >= total
661→        {
662→            // Skip all functions in this and remaining layers.
663→            for remaining_layer in &layers[layer_idx..] {
664→                for func_name in remaining_layer {
665→                    skipped.push(SkippedFunction {
666→                        function_name: func_name.clone(),
667→                        reason: "total scan timeout exceeded".into(),
668→                        category: SkipCategory::Error,
669→                    });
670→                }
671→            }
672→            break;
673→        }
674→
675→        // Build tasks for this layer: each function paired with its mocks.
676→        let mut tasks = Vec::new();
677→        // Track deep FPs computed in this layer (added after the layer completes).
678→        let mut layer_deep_fps: Vec<(String, String)> = Vec::new();
679→
680→        for func_name in layer {
681→            test_order.push(func_name.clone());
682→
683→            let analysis = match analysis_map.get(func_name.as_str()) {
684→                Some(a) => *a,
685→                None => {
686→                    skipped.push(SkippedFunction {
687→                        function_name: func_name.clone(),
688→                        reason: "no analysis found".into(),
689→                        category: SkipCategory::Error,
690→                    });
691→                    continue;
692→                }
693→            };
694→
695→            // Compute shallow fingerprint, then deep fingerprint incorporating callees.
696→            let shallow_fingerprint =
697→                compute_fingerprint_for_function(func_name, analysis, config);
698→
699→            let callees = call_graph.callees(func_name);
700→            let current_deep_fp = shallow_fingerprint.as_ref().map(|sfp| {
701→                crate::fingerprint::compute_deep_fingerprint(sfp, &deep_fingerprints, &callees)
702→            });
703→
704→            // Check resume checkpoint first (uses deep FP).
705→            if let (Some(cache), Some(dfp)) = (&config.cache, &current_deep_fp)
706→                && checkpoint.is_completed(func_name, dfp, cache)
707→                && let Ok(Some(cached_map)) = cache.load(func_name)
708→            {
709→                let mut maps = behavior_maps.lock().await;
710→                maps.insert(func_name.clone(), cached_map);
711→                drop(maps);
712→                layer_deep_fps.push((func_name.clone(), dfp.clone()));
713→                skipped.push(SkippedFunction {
714→                    function_name: func_name.clone(),
715→                    reason: "resumed from checkpoint".into(),
716→                    category: SkipCategory::Expected,
717→                });
718→                continue;
719→            }
720→
721→            // Check cache freshness using deep fingerprint.
722→            if let (Some(cache), Some(dfp)) = (&config.cache, &current_deep_fp)
723→                && let Ok(true) = cache.is_fresh(func_name, dfp)
724→                && let Ok(Some(cached_map)) = cache.load(func_name)
725→            {
726→                let mut maps = behavior_maps.lock().await;
727→                maps.insert(func_name.clone(), cached_map);
728→                drop(maps);
729→                layer_deep_fps.push((func_name.clone(), dfp.clone()));
730→                skipped.push(SkippedFunction {
731→                    function_name: func_name.clone(),
732→                    reason: "unchanged (fingerprint match)".into(),
733→                    category: SkipCategory::Expected,
734→                });
735→                continue;
736→            }
737→
738→            // Try loading cached behavior maps for callees not yet in memory.
739→            if let Some(ref cache) = config.cache {
740→                let mut maps = behavior_maps.lock().await;
741→                for dep in &analysis.dependencies {
742→                    if !maps.contains_key(&dep.symbol)
743→                        && let Ok(Some(cached)) = cache.load(&dep.symbol)
744→                    {
745→                        maps.insert(dep.symbol.clone(), cached);
746→                    }
747→                }
748→                drop(maps);
749→            }
750→
751→            // Build mocks from callees that have already been tested.
752→            let maps = behavior_maps.lock().await;
753→            let mut mocks: Vec<MockConfig> = Vec::new();
754→            let mut mocks_used: Vec<MockUsage> = Vec::new();
755→            for callee in &callees {
756→                if let Some(bmap) = maps.get(callee) {
757→                    mocks.push(mock_config_from_behavior_map(bmap));
758→                    mocks_used.push(MockUsage {
759→                        name: callee.clone(),
760→                        source: MockSource::CachedBehaviorMap,
761→                    });
762→                }
763→            }
764→            drop(maps);
765→
766→            // Generate auto-mocks for remaining unmocked dependencies.
767→            let auto_mocks = crate::auto_mock::generate_auto_mocks(
768→                &analysis.dependencies,
769→                None,
770→                &config.mock_overrides,
771→                &mocks,
772→            );
773→            for am in &auto_mocks {
774→                mocks_used.push(MockUsage {
775→                    name: am.symbol.clone(),
776→                    source: MockSource::TypeAwareStub,
777→                });
778→            }
779→            mocks.extend(auto_mocks);
780→            mocks_used.sort_by(|a, b| a.name.cmp(&b.name));
781→
782→            let file = config
783→                .file_map
784→                .get(func_name)
785→                .cloned()
786→                .unwrap_or_default();
787→
788→            let pool_seeds = {
789→                let pool_guard = input_pool.lock().await;
790→                crate::input_gen::pool_to_candidate_inputs(&analysis.params, &pool_guard)
791→            };
792→
793→            let candidate_inputs = load_config_candidate_inputs(
794→                func_name,
795→                &config.config_dir,
796→                config.max_iterations_per_function,
797→                config.timeout_per_fn.as_secs(),
798→            );
799→

800→            let explore_config = ExploreConfig {
801→                file,
802→                max_iterations: config.max_iterations_per_function,
803→                seed: config.seed,
804→                mocks,
805→                setup_file: None,
806→                setup_mode: crate::config::SetupMode::PerFunction,
807→                value_sources: vec![],
808→                capabilities: crate::orchestrator::FrontendCapabilities::default(),
809→                user_seeds: vec![],
810→                candidate_inputs,
811→                pool_seeds,
812→                project_root: config.project_root.clone(),
813→                loop_buckets: explorer::LoopBuckets::default(),
814→                timeout_explore: config.timeout_explore,
815→            };
816→
817→            tasks.push((func_name.clone(), analysis.clone(), explore_config, mocks_used, callees, current_deep_fp));
818→        }
819→
820→        // Execute tasks in parallel across the worker pool.
821→        // Each task checks out a worker, explores, then returns the worker.
822→        let mut handles = Vec::new();
823→
824→        let fe_config = Arc::new(frontend_config.clone());
825→
826→        for (func_name, analysis, explore_config, mocks_used, callees, deep_fp) in tasks {
827→            let pool = Arc::clone(&pool);
828→            let behavior_maps = Arc::clone(&behavior_maps);
829→            let input_pool = Arc::clone(&input_pool);
830→            let timeout = config.timeout_per_fn;
831→            let cache = config.cache.clone();
832→            let fe_config = Arc::clone(&fe_config);
833→
834→            let handle = tokio::spawn(async move {
835→                let mut frontend = pool.checkout().await;
836→
837→                let result = tokio::time::timeout(
838→                    timeout,
839→                    explore_single_function(
840→                        &mut frontend,
841→                        &func_name,
842→                        &analysis,
843→                        &explore_config,
844→                        &mocks_used,
845→                        &callees,
846→                        &behavior_maps,
847→                        deep_fp.clone(),
848→                        &input_pool,
849→                    ),
850→                )
851→                .await;
852→
853→                let timed_out = result.is_err();
854→
855→                // After a timeout the frontend's stdout buffer contains a
856→                // stale response that would cause an ID mismatch on the next
857→                // request.  Kill and respawn instead of returning to pool.
858→                if timed_out || !frontend.is_alive() {
859→                    // Drop the poisoned/dead frontend (kills the child process).
860→                    drop(frontend);
861→                    match Frontend::spawn(&fe_config).await {
862→                        Ok(new_fe) => pool.return_worker(new_fe).await,
863→                        Err(_) => { /* pool shrinks — acceptable degradation */ }
864→                    }
865→                } else {
866→                    pool.return_worker(frontend).await;
867→                }
868→
869→                match result {
870→                    Ok(Ok(func_result)) => {
871→                        // Store the behavior map for downstream functions.
872→                        let mut maps = behavior_maps.lock().await;
873→                        maps.insert(func_name.clone(), func_result.behavior_map.clone());
874→                        drop(maps);
875→
876→                        // Persist to disk cache for reuse across runs.
877→                        if let Some(ref cache) = cache {
878→                            let _ = cache.store(&func_result.behavior_map);
879→                        }
880→
881→                        FunctionOutcome::Success(Box::new(func_result))
882→                    }
883→                    Ok(Err(e)) => FunctionOutcome::Error {
884→                        function_name: func_name,
885→                        error: e.to_string(),
886→                    },
887→                    Err(_) => FunctionOutcome::Timeout {
888→                        function_name: func_name,
889→                        limit: timeout,
890→                    },
891→                }
892→            });
893→
894→            handles.push(handle);
895→        }
896→
897→        // Collect results from all tasks in this layer.
898→        for handle in handles {
899→            match handle.await {
900→                Ok(FunctionOutcome::Success(result)) => {
901→                    // Record deep FP for this function so downstream layers
902→                    // can incorporate it into their deep fingerprints.
903→                    if let Some(ref fp) = result.behavior_map.fingerprint {
904→                        layer_deep_fps.push((result.function_name.clone(), fp.clone()));
905→                    }
906→                    all_results.push(*result);
907→                }
908→                Ok(FunctionOutcome::Timeout { function_name, limit }) => {
909→                    skipped.push(SkippedFunction {
910→                        function_name,
911→                        reason: format!("timed out after {:.0}s", limit.as_secs_f64()),
912→                        category: SkipCategory::Error,
913→                    });
914→                }
915→                Ok(FunctionOutcome::Error { function_name, error }) => {
916→                    skipped.push(SkippedFunction {
917→                        function_name,
918→                        reason: format!("error: {error}"),
919→                        category: SkipCategory::Error,
920→                    });
921→                }
922→                Err(e) => {
923→                    // JoinError (task panicked or was cancelled)
924→                    skipped.push(SkippedFunction {
925→                        function_name: "(unknown)".into(),
926→                        reason: format!("task join error: {e}"),
927→                        category: SkipCategory::Error,
928→                    });
929→                }
930→            }
931→        }
932→
933→        // Merge this layer's deep fingerprints into the accumulated map.
934→        for (name, fp) in layer_deep_fps {
935→            checkpoint.mark_completed(&name, &fp);
936→            deep_fingerprints.insert(name, fp);
937→        }
938→
939→        // Persist checkpoint after each layer completes.
940→        checkpoint.layer_index = layer_idx;
941→        if let Some(ref path) = config.resume_path {
942→            let _ = checkpoint.save(path);
943→        }
944→    }
945→
946→    // Save the interesting input pool if configured.
947→    if let Some(ref pool_path) = config.pool_path {
948→        let pool_guard = input_pool.lock().await;
949→        if let Err(e) = interesting_pool::save_pool(&pool_guard, pool_path) {
950→            log::warn!("failed to save interesting pool: {e}");
951→        }
952→    }
953→
954→    // Shutdown workers. All spawned tasks have completed, so this is the only
955→    // remaining reference to the pool.
956→    if let Ok(pool) = Arc::try_unwrap(pool) {
957→        pool.shutdown().await;
958→    }
959→
960→    Ok(ParallelScanResult {
961→        function_results: all_results,
962→        test_order,
963→        skipped,
964→        workers_used: effective_parallelism,
965→        sampling: None,
966→    })
967→}
