969→/// Build exploration layers from test order entries and call graph.
970→///
971→/// Functions are grouped into layers such that all callees of functions in
972→/// layer N appear in layers 0..N-1. Functions within the same layer can
973→/// be explored in parallel.
974→fn build_layers(order_entries: &[TestOrderEntry], call_graph: &CallGraph) -> Vec<Vec<String>> {
975→    // The test_order from the behavior::CallGraph is already topologically sorted
976→    // (leaves first). We group consecutive entries that share no cross-dependencies
977→    // into the same layer. For simplicity, we assign each entry its own layer slot
978→    // and then could merge, but the simplest correct approach is:
979→    // layer 0 = functions with no callees in the scan set
980→    // layer N = functions whose callees are all in layers < N
981→    //
982→    // Since test_order is already leaves-first, we can build layers by tracking
983→    // which functions are "done" after each layer.
984→
985→    let all_functions: Vec<String> = order_entries
986→        .iter()
987→        .flat_map(|entry| match entry {
988→            TestOrderEntry::Single { function_id, .. } => vec![function_id.clone()],
989→            TestOrderEntry::MutualGroup { function_ids } => function_ids.clone(),
990→        })
991→        .collect();
992→
993→    if all_functions.is_empty() {
994→        return Vec::new();
995→    }
996→
997→    let mut assigned: HashMap<String, usize> = HashMap::new();
998→    let mut layers: Vec<Vec<String>> = Vec::new();
999→

1000→    for func_name in &all_functions {
1001→        let callees = call_graph.callees(func_name);
1002→        let max_callee_layer = callees
1003→            .iter()
1004→            .filter_map(|c| assigned.get(c))
1005→            .copied()
1006→            .max();
1007→
1008→        let my_layer = match max_callee_layer {
1009→            Some(l) => l + 1,
1010→            None => 0,
1011→        };
1012→
1013→        while layers.len() <= my_layer {
1014→            layers.push(Vec::new());
1015→        }
1016→        layers[my_layer].push(func_name.clone());
1017→        assigned.insert(func_name.clone(), my_layer);
1018→    }
1019→
1020→    layers
1021→}
