1104→/// Format a parallel scan result as a human-readable report.
1105→pub fn format_parallel_scan_report(result: &ParallelScanResult) -> String {
1106→    let mut out = String::new();
1107→
1108→    if let Some(ref ctx) = result.sampling {
1109→        let pct = if ctx.total_functions > 0 {
1110→            (ctx.sampled_functions as f64 / ctx.total_functions as f64 * 100.0).round() as usize
1111→        } else {
1112→            0
1113→        };
1114→        out.push_str(&format!(
1115→            "Explored {}/{} functions ({}% core sample, {} via dependency closure)\n",
1116→            ctx.sampled_functions + ctx.closure_functions,
1117→            ctx.total_functions,
1118→            pct,
1119→            ctx.closure_functions,
1120→        ));
1121→    }
1122→
1123→    let expected: Vec<_> = result.skipped.iter().filter(|s| s.category == SkipCategory::Expected).collect();
1124→    let errors: Vec<_> = result.skipped.iter().filter(|s| s.category == SkipCategory::Error).collect();
1125→
1126→    out.push_str(&format!(
1127→        "Scan complete: {} function(s) tested, {} skipped, {} error(s) ({} worker(s))\n",
1128→        result.function_results.len(),
1129→        expected.len(),
1130→        errors.len(),
1131→        result.workers_used,
1132→    ));
1133→
1134→    for func_result in &result.function_results {
1135→        out.push_str(&format!("\n-- {} --\n", func_result.function_name));
1136→        out.push_str(&explorer::format_exploration_report_verbose(
1137→            &func_result.exploration,
1138→        ));
1139→
1140→        if !func_result.mocks_used.is_empty() {
1141→            out.push_str(&format!(
1142→                "  Mocks used: {}\n",
1143→                format_mocks_used(&func_result.mocks_used)
1144→            ));
1145→        }
1146→
1147→        for cov in &func_result.behavior_coverage {
1148→            let exercised = cov.exercised_behavior_ids.len();
1149→            let total = cov.total_behaviors;
1150→            let pct = if total > 0 {
1151→                (exercised as f64 / total as f64 * 100.0).round()
1152→            } else {
1153→                0.0
1154→            };
1155→            out.push_str(&format!(
1156→                "  Behavior coverage of {}: {}/{} ({pct:.0}%)\n",
1157→                cov.callee, exercised, total
1158→            ));
1159→        }
1160→    }
1161→
1162→    format_skip_sections(&expected, &errors, &mut out);
1163→
1164→    out
1165→}
