1167→/// Format a scan result as a human-readable report.
1168→pub fn format_scan_report(result: &ScanResult) -> String {
1169→    let mut out = String::new();
1170→
1171→    if let Some(ref ctx) = result.sampling {
1172→        let pct = if ctx.total_functions > 0 {
1173→            (ctx.sampled_functions as f64 / ctx.total_functions as f64 * 100.0).round() as usize
1174→        } else {
1175→            0
1176→        };
1177→        out.push_str(&format!(
1178→            "Explored {}/{} functions ({}% core sample, {} via dependency closure)\n",
1179→            ctx.sampled_functions + ctx.closure_functions,
1180→            ctx.total_functions,
1181→            pct,
1182→            ctx.closure_functions,
1183→        ));
1184→    }
1185→
1186→    let expected: Vec<_> = result.skipped_functions.iter().filter(|s| s.category == SkipCategory::Expected).collect();
1187→    let errors: Vec<_> = result.skipped_functions.iter().filter(|s| s.category == SkipCategory::Error).collect();
1188→
1189→    out.push_str(&format!(
1190→        "Scan complete: {} function(s) tested\n",
1191→        result.function_results.len()
1192→    ));
1193→
1194→    for func_result in &result.function_results {
1195→        out.push_str(&format!("\n── {} ──\n", func_result.function_name));
1196→
1197→        out.push_str(&explorer::format_exploration_report_verbose(&func_result.exploration));
1198→
1199→        if !func_result.mocks_used.is_empty() {
